import java.util.*;public class PeakElement{static int p(int[]a){int l=0,r=a.length-1;while(l<r){int m=l+(r-l)/2;if(a[m]<a[m+1])l=m+1;else r=m;}return l;}public static void main(String[]x){Scanner s=new Scanner(System.in);int n=s.nextInt();int[]a=new int[n];for(int i=0;i<n;i++)a[i]=s.nextInt();int i=p(a);System.out.println(i);System.out.println(a[i]);}}